// Normaliza a formato +E.164 (por defecto Espana, +34). Debe coincidir con la logica del bridge de entrada.
function normalizePhone(raw, defaultCC = '34') {
  if (raw === undefined || raw === null) return null;
  const hasPlus = String(raw).trim().startsWith('+');
  const d = String(raw).replace(/\D/g, '');
  if (!d) return null;
  if (hasPlus) return '+' + d;
  if (d.startsWith('00')) return '+' + d.slice(2);
  if (d.length === 9 && /^[6-9]/.test(d)) return '+' + defaultCC + d;
  return '+' + d;
}

